1	/// Beamr — a Rust runtime with the BEAM's execution model.
2	///
3	/// Loads `.beam` bytecode produced by the Gleam toolchain (via `erlc`)
4	/// and executes it with preemptive scheduling, per-process isolation,
5	/// supervision primitives, and a native function interface.
6	pub mod atom;
7	pub mod error;
8	pub mod gc;
9	pub mod hook;
10	pub mod interpreter;
11	pub mod loader;
12	pub mod mailbox;
13	pub mod module;
14	pub mod native;
15	pub mod process;
16	pub mod scheduler;
17	pub mod supervision;
18	pub mod term;
19	pub mod timer;

1	/// Term representation — what all data is made of.
2	///
3	/// A term is a single 64-bit machine word with low-bit tagging.
4	/// Immediates (small integers, atoms, pids, nil) fit entirely in
5	/// the word. Boxed values (tuples, lists, binaries, floats, big
6	/// integers, closures, maps, references) are tagged pointers into
7	/// the process-local heap.
8	pub mod binary;
9	pub mod boxed;
10	pub mod compare;

